// ==================== HELPERS ====================

// Normaliza conteúdo vindo do Google Docs
function normalizeContent(str) {
  if (!str) return "";
  // Trata objetos vindos como JSON do Google Docs
  if (typeof str === "object") {
    try {
      str = JSON.stringify(str);
    } catch (_) {
      str = String(str);
    }
  }

  return String(str)

    // Remove HTML e tabelas
    .replace(/<[^>]+>/g, " ")

    // Remove markdown de tabela do Google Docs (| coluna | valor |)
    .replace(/\|+/g, " ")

    // Normaliza símbolos de hífen e traço (Google Docs usa caracteres Unicode estranhos)
    .replace(/[–—−]/g, "-")

    // Insere quebras ANTES de cada novo dia (1º dia, 2º dia, Dia 3 etc)
    .replace(/(?=(?:\b\d+\s*(?:º|o)?\s*dia\b|\bdia\s*\d+\b))/gi, "\n")

    // Corrige quando o hífen fica colado no número (ex: "1ºdia-" → "1º dia -")
    .replace(/(\d+\s*(?:º|o)?\s*)dia\s*[-–—]?\s*/gi, (_, p1) => `${p1}dia - `)

    // Garante quebra antes e depois de “Refeições:”
    .replace(/Refei(?:ç|c)ões?:/gi, "\nRefeições:")

    // Remove múltiplas quebras seguidas
    .replace(/\r/g, "\n")
    .replace(/\n{2,}/g, "\n")

    // Remove espaços repetidos
    .replace(/[ \t]{2,}/g, " ")

    // Normaliza barras / que vêm grudadas (Beijing/Xian → Beijing / Xian)
    .replace(/([A-Za-zÁÉÍÓÚÂÊÔÃÕÇ])\/([A-Za-zÁÉÍÓÚÂÊÔÃÕÇ])/g, "$1 / $2")

    // Corrige “...” e “ ..” para “...”
    .replace(/\s*\.\.\.\s*/g, " ... ")

    .trim();
}
// Função para extrair texto entre 2 regex
function between(text, startRegex, endRegex) {
  const start = text.search(startRegex);
  if (start === -1) return "";
  const rest = text.slice(start);
  if (!endRegex) return rest.trim();
  const end = rest.search(endRegex);
  if (end === -1) return rest.trim();
  return rest.slice(0, end).trim();
}


// ==================== PARSER SAÍDAS ====================
function parseSaidas(text) {
  if (!text) return [];

  let s = String(text).replace(/\r/g, ' ').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();

  // 0 - Saídas: Diárias, conforme calendário de partidas.
  const regexFull = /(Sa[ií]das?:\s*Diárias, conforme calendário de partidas\.)/i;
  const matchFull = s.match(regexFull);

  // 1 - Diárias, conforme calendário de partidas.
  const regexFreq = /(Diárias, conforme calendário de partidas\.)/i;
  const matchFreq = s.match(regexFreq);

  // 2 - Mínimo de 2 participantes
  const regexMin = /(M[ií]nimo de \d+ participantes)/i;
  const matchMin = s.match(regexMin);

  const arr = [];
  if (matchFull) arr.push(matchFull[1].trim());
  if (matchFreq) arr.push(matchFreq[1].trim());
  if (matchMin) arr.push(matchMin[1].trim());

  // 3 - Roteiro entre "partidas." e "Mínimo..."
  if (matchFreq && matchMin) {
    const startIdx = s.indexOf(matchFreq[1]) + matchFreq[1].length;
    const endIdx = s.indexOf(matchMin[1]);
    if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
      const roteiro = s.slice(startIdx, endIdx).trim();
      if (roteiro) arr.push(roteiro);
    }
  }

  return arr;
}
// Extrai itinerário de forma universal (funciona para texto limpo e quebrado)
function extractItinerary(text) {
  if (!text) return "";

  const raw = String(text);

  // ENCONTRA "1º dia", "1o dia", "1 dia", "Dia 1"
  const inicioRegex = /(1\s*(?:º|o)?\s*dia|dia\s*1)/i;
  const matchInicio = raw.match(inicioRegex);

  if (!matchInicio) return "";

  const start = raw.indexOf(matchInicio[0]);

  // Cortamos DALI PARA FRENTE — nada antes importa
  let sub = raw.slice(start);

  // Agora procuramos o fim real
  const fimRegex = /(Fim dos serviços\.|FIM DOS SERVIÇOS\.|Fim de nossos serviços\.)/i;
  const matchFim = sub.match(fimRegex);

  if (matchFim) {
    const end = sub.indexOf(matchFim[0]) + matchFim[0].length;
    sub = sub.slice(0, end);
  }

  // Limpeza suave sem destruir linhas
  sub = sub
    .replace(/\r/g, "")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{2,}/g, "\n")
    .trim();

  return sub;
}
// ==================== PROCESSA TODOS ====================
const results = items.map(item => {
  const content = normalizeContent(item.json.content || "");
  const titulo = item.json.nome || "";
  const tables = item.json.tables || [];
  const hoteisHtml = item.json.hoteis || ""; 
  const calendarioHtml = item.json.calendario || "";

  // Prévia -> de "Saídas:" até "1º dia"
  const previa = between(content, /Sa[ií]das?:/i, /1(?:º|o)?\s*dia/i);

  // ✅ Novo recorte de itinerário (universal)
  const itinerario = extractItinerary(content);

  // Observações -> entre títulos tradicionais
  let observacoes = between(
    content,
    /Observa[cç][oõ]es/i,
    /Documentos\s+necess[aá]rios/i
  );
  if (!observacoes) {
    const altMatch = content.match(
      /(Todos\s+os\s+pre[cç]os[\s\S]*?(?:confirma[cç][aã]o\s+da\s+reserva\.|(?=Passaporte\s+com\s+validade)))/i
    );
    if (altMatch) observacoes = altMatch[1].trim();
  }

  // Documentos
  let documentos = between(content, /Documentos\s+necess[aá]rios/i, /Pacote\s+Inclui/i);
  if (!documentos) {
    const altMatch = content.match(
      /(Passaporte\s+com\s+validade[\s\S]*?(?:Para\s+passageiros\s+portadores\s+de\s+passaporte\s+de\s+outras\s+nacionalidades[\s\S]*?competentes\.|(?=Hospedagem)))/i
    );
    if (altMatch) documentos = altMatch[1].trim();
  }

  // Inclui
  let inclui = between(content, /Pacote\s+Inclui/i, /Pacote\s+N[aã]o\s+Inclui/i);
  if (!inclui) {
    const altMatch = content.match(
      /(Hospedagem\s+nos\s+hot[eé]is[\s\S]*?(?:Ingressos\s+dos\s+monumentos\s+e\s+locais\s+visitados\.|(?=Parte\s+a[eé]rea\s+internacional)))/i
    );
    if (altMatch) inclui = altMatch[1].trim();
  }

  // Não Inclui
  let naoInclui = between(content, /Pacote\s+N[aã]o\s+Inclui/i, /(Hot[eé]is\s+previstos.*|Informa[cç][oõ]es\s+Gerais)/i);
  if (!naoInclui) {
    const altMatch = content.match(
      /(Taxas\s+de\s+embarque[\s\S]*?(?:Quaisquer\s+despesas\s+extras.*?programa\.|(?=\*\s*Para\s+reservas)))/i
    );
    if (altMatch) naoInclui = altMatch[1].trim();
  }

  return {
    json: {
      titulo,
      previa,
      itinerario,
      observacoes,
      documentos,
      inclui,
      naoInclui,
      hoteis: hoteisHtml,
      calendario: calendarioHtml,
      tables
    }
  };
});

return results;

// Pega todos os itens
const allItems = $input.all();
let results = [];

// PREPARAÇÃO (BACKUP):
// Caso o Agente tenha retornado uma LISTA de mapas no primeiro item
let listaDeMapas = [];
try {
    let rawOutput = $input.first().json.output;
    if (Array.isArray(rawOutput)) {
        listaDeMapas = rawOutput;
    } else if (rawOutput) {
        listaDeMapas = [rawOutput];
    }
} catch (e) {}

// LOOP PRINCIPAL
for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];
  const data = item.json;

  // Lógica de Seleção do Mapa
  let mapaAtual = "";
  if (data.output && typeof data.output === 'string') {
      mapaAtual = data.output;
  }
  else if (listaDeMapas.length > i && listaDeMapas[i]) {
      mapaAtual = listaDeMapas[i];
  }
  if (!mapaAtual && Array.isArray(data.output)) {
      mapaAtual = data.output[0];
  }

  const titulo = data.titulo;
  const itinerario = data.itinerarioArray || [];

  // Início do HTML
  let itinerarioHtml = `
  <div style="display: flex; justify-content: flex-start; align-items: flex-start; gap: 20px; flex-wrap: wrap; margin-top: 10px;">
      <div style="flex: 1 1 48%; min-width: 320px; box-sizing: border-box;">
      <h3 style="font-family: Helvetica;">ITINERÁRIO</h3>
  `;

  // Loop dos dias
  for (const it of itinerario) {
    let rawDia = it.dia ?? it.tituloDia ?? "";
    let tituloDia = Array.isArray(rawDia) ? rawDia.filter(Boolean).join(" ").trim() : String(rawDia).trim();

    // 1. Prepara o texto do Opcional
    let opcionalRaw = it.opcionalSugerido || [];
    let textoOpcionalLimpo = "";

    if (Array.isArray(opcionalRaw) && opcionalRaw.length > 0) {
        textoOpcionalLimpo = opcionalRaw.join("; ");
    } else if (typeof opcionalRaw === 'string') {
        textoOpcionalLimpo = opcionalRaw.trim();
    }

    // 2. Limpeza do Conteúdo
    let conteudo = (it.conteudo || "")
        .replace(/<br\s*\/?>/gi, " ")
        .replace(/\n+/g, " ")
        .replace(/\s+/g, " ")
        .trim();

    // --- CORREÇÃO DA DUPLICIDADE ---
    if (textoOpcionalLimpo.length > 5) { 
        // Cria regex segura escapando caracteres especiais
        const regexTexto = textoOpcionalLimpo.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const regexRemocao = new RegExp(regexTexto, 'gi');

        // Remove o texto do opcional de dentro do conteúdo
        conteudo = conteudo.replace(regexRemocao, "");
        // Remove prefixos soltos no final
        conteudo = conteudo.replace(/(Opcional|Sugestão|Opcional Sugerido)\s*[-–:]*\s*$/i, "").trim();
        conteudo = conteudo.replace(/\.\s*\.$/, ".");
    }

    // 3. Monta o HTML do Opcional (Cor Cinza + Sem buraco extra)
    let opcionalHtml = "";
    if (textoOpcionalLimpo) {
        // MUDANÇA AQUI:
        // 1. Removi o <br> do início (ele vai colar na linha de baixo do conteúdo)
        // 2. Adicionei style="color: #666666" (Cinza Escuro/Claro)
        opcionalHtml = `<span style="color: #666666;">${textoOpcionalLimpo}</span><br>\n`;
    }

    // 4. Refeições
    let refeicoesRaw = (it.refeicoes || "").trim();
    let refeicoesHtml = "";
    if (refeicoesRaw && refeicoesRaw !== "-") { 
      let textoRefeicao = /refeiç/i.test(refeicoesRaw) ? refeicoesRaw : `Refeições: ${refeicoesRaw}`;
      refeicoesHtml = `<em>${textoRefeicao}</em><br>\n`;
    } else if (refeicoesRaw === "-" || refeicoesRaw === "-.") {
       refeicoesHtml = `<em>Refeições: -.</em><br>\n`;
    }

    // Montagem final do dia
    itinerarioHtml += `<strong>${tituloDia}</strong><br>\n`;

    // Conteúdo adiciona um <br> no final, então o opcional entra na próxima linha
    if (conteudo) itinerarioHtml += `<span>${conteudo}</span><br>\n`;

    if (opcionalHtml) itinerarioHtml += `${opcionalHtml}`;
    if (refeicoesHtml) itinerarioHtml += `${refeicoesHtml}`;

    itinerarioHtml += `<br>\n`; 
  }

  // Inserção do Mapa
  itinerarioHtml += `
      </div>
      <div style="flex: 1 1 35%; min-width: 340px; display: flex; justify-content: flex-end; align-items: flex-start; margin-left: 30px;">
        <div style="width: 100%; max-width: 520px; height: 480px; border-radius: 12px; overflow: hidden; background: transparent !important; box-shadow: none !important; ${!mapaAtual ? 'border: 1px dashed #ccc;' : ''}">
          <div style="width: 100%; height: 100%; background: transparent !important; border: none !important; margin: 0; padding: 0;">
            ${mapaAtual || '<p style="text-align:center; color:#999; padding-top:100px;">Mapa indisponível</p>'}
          </div>
        </div>
      </div>
    </div>
    <style>@media (min-width: 900px) { .itinerario-flex-container { display: flex !important; flex-wrap: nowrap !important; align-items: flex-start !important; } }</style>
  `;

  results.push({
    json: {
      ...data,
      titulo,
      itinerarioHtml,
      tituloAHtml: data.tituloAHtml || "",
      previaHtml: data.previaHtml || "",
      observacoesArray: data.observacoesArray || [],
      documentosArray: data.documentosArray || [],
      incluiArray: data.incluiArray || [],
      naoIncluiArray: data.naoIncluiArray || [],
      naoIncluiParsed: data.naoIncluiParsed || [],
      hoteisArray: data.hoteisArray || [],
      calendarioArray: data.calendarioArray || [],
      itinerarioArray: data.itinerarioArray || [],
      cidades: data.cidades || [],
      mapa_automatico: mapaAtual 
    }
  });
}

return results;

