// Pega todos os itens que chegam ao Code Node (cada item é um roteiro diferente)
const allItems = $input.all();
let results = [];

// Fallback caso documentosArray venha vazio
const fallbackDocs = $input.first().json.documentosArray || [];

// ------------------------------
// Funções utilitárias
// ------------------------------
function normalizeText(value) {
  if (value == null) return "";
  if (typeof value === "string") return value.trim();
  if (typeof value === "number" || typeof value === "boolean") return String(value).trim();
  if (Array.isArray(value)) {
    return value.map(v => normalizeText(v)).filter(Boolean).join(" ");
  }
  if (typeof value === "object") {
    const keys = ["text","texto","conteudo","conteúdo","titulo","titulo_text","item","itens","descricao","description","value"];
    for (const k of keys) {
      if (k in value && value[k] != null) {
        const t = normalizeText(value[k]);
        if (t) return t;
      }
    }
    const vals = Object.values(value).map(v => normalizeText(v)).filter(Boolean);
    if (vals.length) return vals.join(" ");
    try { return JSON.stringify(value); } catch(e){ return ""; }
  }
  return "";
}

function isComEstrelaText(text) {
  if (!text) return false;
  const t = text.toLowerCase().replace(/\s+/g, "");
  return t === "comestrela" || t === "titulo:comestrela" || /^titulo[:\s]*comestrela$/i.test(text);
}

// ------------------------------
// PROCESSAMENTO
// ------------------------------
for (const item of allItems) {
  const data = item.json;

  // RECEBE TUDO, COMPLETO
  const documentosArray = data.documentosArray?.length ? data.documentosArray : fallbackDocs;

  const observacoesParsed = data.observacoesParsed || [];

  // --------------------------
  // 🔷 HTML das OBSERVAÇÕES
  // --------------------------
  let ObservacoesHtml = `
<!--Observações-->  
<br><span style="font-family: Helvetica; font-size:12pt;"><strong><em>
Observações:</em></strong></span><br>
  `;

  for (const bloco of observacoesParsed) {
    const titulo = bloco.titulo?.trim() || null;
    const itens = Array.isArray(bloco.itens) ? bloco.itens : [];

    if (titulo) {
      ObservacoesHtml += `
<span style="font-family: Helvetica; font-size:12pt;"><strong>${titulo}:</strong></span><br>`;
    }

    itens.forEach(it => {
      if (!it?.trim()) return;
      ObservacoesHtml += `
[icon color="Extra-Color-1" Animation_speed="Slow" size="tiny" image="fa-chevron-right"] ${it.trim()}<br>`;
    });

    ObservacoesHtml += `<br>`;
  }

  // --------------------------
  // 🔷 HTML dos DOCUMENTOS
  // --------------------------
  let documentosHtml = `
<!--Documentos-->  
<br><span style="font-size: 12pt; font-family: Helvetica;">
   <em><strong>Documentos necessários para portadores de passaporte brasileiro:</strong></em>
</span><br>
  `;

  documentosArray.forEach((doc) => {

    // Bloco com títulos e itens (comestrela style)
    if (doc && typeof doc === "object" && Array.isArray(doc.itens)) {
      const blocoTitulo = normalizeText(doc.titulo || "");

      if (blocoTitulo && !isComEstrelaText(blocoTitulo)) {
        documentosHtml += `
<br><span style="font-size: 11pt; font-family: Helvetica;"><strong>${blocoTitulo}</strong></span><br>`;
      }

      doc.itens.forEach(it => {
        const t = normalizeText(it);
        if (t) documentosHtml += `<br>* ${t}`;
      });

      return;
    }

    // Objeto com itens simples
    if (doc && typeof doc === "object" && doc.itens && !Array.isArray(doc.itens)) {
      const blocoTitulo = normalizeText(doc.titulo || "");
      if (blocoTitulo && !isComEstrelaText(blocoTitulo)) {
        documentosHtml += `
<br><span style="font-size: 11pt; font-family: Helvetica;"><strong>${blocoTitulo}</strong></span><br>`;
      }

      const t = normalizeText(doc.itens);
      if (t) documentosHtml += `* ${t}<br>`;
      return;
    }

    // Caso normal
    const text = normalizeText(doc);
    if (!text || isComEstrelaText(text)) return;

    if (/^titulo:/i.test(text)) {
      documentosHtml += `
<br><span style="font-size: 11pt; font-family: Helvetica;">
<strong>${text.replace(/^titulo:/i, "").trim()}</strong>
</span><br>`;
      return;
    }

    documentosHtml += `
