const allItems = $input.all();
let results = [];

// ============================================================
// 1. HELPERS: PARSER E FORMATAÇÃO
// ============================================================

function parseHtmlTableToMatrix(htmlString) {
  const rows = [];
  const cleanHtml = htmlString.replace(/[\r\n]+/g, " ");
  const rowMatches = cleanHtml.match(/<tr[^>]*>[\s\S]*?<\/tr>/gi) || [];

  for (const rowHtml of rowMatches) {
    const rowData = [];
    const cellMatches = rowHtml.match(/<(td|th)[^>]*>[\s\S]*?<\/\1>/gi) || [];
    for (const cell of cellMatches) {
      let text = cell.replace(/<[^>]+>/g, "").trim();
      text = text.replace(/&nbsp;/g, " ");
      rowData.push(text);
    }
    if (rowData.length > 0) rows.push(rowData);
  }
  return rows;
}

function formatarTexto(texto) {
  if (!texto) return "";
  // Formata datas (Mês/Ano:) e quebra linha para visual limpo
  const regexData = /([A-Za-zç]+\/\d{4}):/g;
  if (regexData.test(texto)) {
     return texto.replace(/([A-Za-zç]+\/\d{4}:)/g, "<br><strong>$1</strong>");
  }
  return texto;
}

function extractDatesSimple(matrix) {
    const dates = [];
    for (let row of matrix) {
        const cell = row.find(c => (/\d/.test(c) || /\//.test(c)) && c.length > 5 && !c.toUpperCase().includes("SAÍDA"));
        if (cell) dates.push(cell);
    }
    return dates;
}

// ============================================================
// 2. PROCESSAMENTO PRINCIPAL
// ============================================================
for (const item of allItems) {
  const original = item.json;
  let calendarioHtml = "";

  let allMatrices = [];

  // Extração das matrizes
  if (original.calendarios && Array.isArray(original.calendarios)) {
     if (original.calendarios[0] && original.calendarios[0].linhas) {
        allMatrices = original.calendarios.map(c => c.linhas);
     } else {
        allMatrices = [original.calendarios]; 
     }
  } else {
     const jsonStr = JSON.stringify(original);
     const tableMatches = jsonStr.match(/<table[^>]*>([\s\S]*?)<\/table>/gi) || [];
     allMatrices = tableMatches.map(t => parseHtmlTableToMatrix(t));
  }

  // --- VARIÁVEIS DE RESULTADO ---
  let seasonPairs = []; 
  let stdDates = [];    
  let supDates = [];    
  let validadeDates = []; 

  let dynamicHeader = "DATAS DE SAÍDA"; 

  // --- LOOP DE ANÁLISE ---
  for (const matrix of allMatrices) {
      if (matrix.length < 2) continue;

      const fullText = JSON.stringify(matrix).toUpperCase();

      // =========================================================
      // [NOVO] FILTRO ANTI-LIXO (SERVIÇOS OPCIONAIS)
      // =========================================================
      // Verifica as 3 primeiras linhas em busca de termos que indicam tabela de preço opcional
      const headerCheck = matrix.slice(0, 3).map(r => r.join(" ").toUpperCase()).join(" ");

      const termosProibidos = [
          "SERVIÇOS OPCIONAIS", "SERVICOS OPCIONAIS", 
          "SERVIÇO OPCIONAL", "SERVICO OPCIONAL",
          "MEIA PENSÃO", "PENSÃO COMPLETA", "PENSAO COMPLETA",
          "SUPLEMENTO", "OPCIONAIS -"
      ];

      // Se tiver termo proibido e NÃO tiver a palavra "SAÍDA" ou "PARTIDA" explícita no mesmo cabeçalho, pula.
      if (termosProibidos.some(termo => headerCheck.includes(termo)) && !headerCheck.includes("SAÍDA") && !headerCheck.includes("PARTIDA")) {
          continue; 
      }

      // Filtro extra: Se tiver "Período" e "Standard" mas não tiver "Saída", provavelmente é tabela de preço
      if (headerCheck.includes("PERÍODO") && headerCheck.includes("STANDARD") && !headerCheck.includes("SAÍDA")) {
          continue;
      }

      let captured = false; 

      // ---------------------------------------------------------
      // 1. [NOVO] DETECÇÃO POR PADRÃO DE CONTEÚDO (Datas e Intervalos)
      // ---------------------------------------------------------
      let dateColIndex = -1;

      // AJUSTE: Procura coluna que tem Mês/Ano: OU formato Dia/Mês OU Dia de Mês
      for(let r = 0; r < Math.min(10, matrix.length); r++) {
         const row = matrix[r];
         const foundIdx = row.findIndex(c => {
             if (!c || c.length < 5) return false;

             // Padrão 1: Abril/2025:
             const isStandard = /[A-Za-zç]+\/\d{4}:/.test(c);

             // Padrão 2: 01/Novembro a ... (Começa com dia/mês e tem range)
             // O Regex `[\s\/]+` aceita barra ou espaço (01/Nov ou 01 Nov)
             const hasDateStart = /\d{1,2}[\s\/]+[A-Za-zç]+/.test(c);
             const hasRangeMarkers = (c.includes(" a ") || c.includes("/20") || c.includes(" e "));

             // Anti-ruído: não pode ter "participante" (evita pegar coluna de preços)
             const isNotNoise = !c.toLowerCase().includes("participante");

             return (isStandard || (hasDateStart && hasRangeMarkers)) && isNotNoise;
         });

         if (foundIdx !== -1) {
            dateColIndex = foundIdx;
            break;
         }
      }

      if (dateColIndex !== -1) {
         // --- DETECÇÃO DE CABEÇALHO DINÂMICO ---
         for (let i = 0; i < Math.min(3, matrix.length); i++) {
             const candidate = (matrix[i][dateColIndex] || "").trim();
             if (/sa[ií]das?|partidas?|di[áa]rias?|semanais|segunda|terça|quarta|quinta|sexta|s[áa]bado|domingo/i.test(candidate)) {
                 dynamicHeader = candidate; 
                 matrix[i][dateColIndex] = "IGNORE_HEADER"; 
                 break; 
             }
         }

         // --- EXTRAÇÃO DOS DADOS ---
         for (let row of matrix) {
            const txt = row[dateColIndex];

            if (!txt || txt === "IGNORE_HEADER") continue;

            // Filtros de lixo
            if (txt.toUpperCase().includes("SINGLE")) continue;
            if (txt.toUpperCase().includes("DUPLO")) continue;
            if (txt.toUpperCase().includes("TRIPLO")) continue;
            if (txt.toLowerCase().includes("participante")) continue; // Proteção extra

            // Validações de Formato
            const isStandardDate = /[A-Za-zç]+\/\d{4}:/.test(txt);

            // Regex ajustado: Aceita "01 Novembro" (Espaço) ou "01/Novembro" (Barra)
            const isRangeDate = /\d{1,2}[\s\/]+[A-Za-zç]+/.test(txt) && txt.length > 5 && (txt.includes(" a ") || txt.includes("/20"));

            const isLooseDate = /\d{2}\/\d{2}/.test(txt) && txt.length > 5;

            if (isStandardDate || isRangeDate || isLooseDate) {
               // DEDUPLICAÇÃO:
               // Evita adicionar a mesma data duas vezes seguidas (comum quando a data ocupa várias linhas na tabela original)
               const lastItem = seasonPairs[seasonPairs.length - 1];
               if (lastItem && lastItem.date === txt) {
                   continue;
               }

               seasonPairs.push({ group: "Auto", date: txt });
               captured = true;
            }
         }
      }

      if (captured) continue; 

      // ---------------------------------------------------------
      // 2. [ANTIGO] DETECÇÃO POR CABEÇALHO EXPLÍCITO
      // ---------------------------------------------------------
      let idxTemp = -1;
      let idxSaida = -1;
      let headerRow = -1;

      for(let i=0; i<Math.min(5, matrix.length); i++) {
          const rowStr = matrix[i].map(c => c.toUpperCase());
          if (rowStr.includes("TEMPORADA") || rowStr.some(c => c.includes("GRUPOS"))) idxTemp = matrix[i].findIndex(c => c.toUpperCase().includes("TEMPORADA") || c.toUpperCase().includes("GRUPO"));
          if (rowStr.some(c => c.includes("SAÍDA") || c.includes("SAIDA"))) idxSaida = matrix[i].findIndex(c => c.toUpperCase().includes("SAÍDA") || c.toUpperCase().includes("SAIDA"));

          if (idxTemp !== -1 && idxSaida !== -1) {
              headerRow = i;
              break;
          }
      }

      if (idxTemp !== -1 && idxSaida !== -1) {
          for (let i = headerRow + 1; i < matrix.length; i++) {
              const group = matrix[i][idxTemp];
              const date = matrix[i][idxSaida];
              if (group && group.trim().length > 0 && date && (/\d/.test(date) || date.length > 5)) {
                  seasonPairs.push({ group: group, date: date });
                  captured = true;
              }
          }
      }

      if (captured) continue;

      // ---------------------------------------------------------
      // 3. [ANTIGO] FALLBACKS
      // ---------------------------------------------------------
      if (fullText.includes("STANDARD") && fullText.includes("SUPERIOR")) {
          const dates = extractDatesSimple(matrix);
          if (dates.length > 0) stdDates = dates; 
      }
      else if (fullText.includes("VALIDADE")) {
          for (let row of matrix) {
             const cell = row.find(c => String(c).length > 10 && !c.toUpperCase().includes("VALIDADE") && /\d/.test(c));
             if (cell) validadeDates.push(cell);
          }
      }
  }

  // ============================================================
  // GERADOR DE HTML
  // ============================================================

  if (seasonPairs.length > 0) {
      let rowsHtml = "";
      const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";

      seasonPairs.forEach((item, index) => {
          let label = "";
          if (item.group === "Auto" || item.group === "Saída" || !item.group) {
              label = alphabet[index] || (index + 1); 
          } else {
              label = item.group;
          }

          rowsHtml += `
            <tr>
                <td style="text-align:center; font-weight:bold; width: 10%; vertical-align: middle;">${label}</td>
                <td style="padding:10px; text-align:left; vertical-align: middle;">${formatarTexto(item.date)}</td>
            </tr>`;
      });

      calendarioHtml = buildTable("GRUPOS", dynamicHeader, null, rowsHtml);
  }

  else if (stdDates.length > 0) {
      let rowsHtml = "";
      const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
      for (let i = 0; i < stdDates.length; i++) {
          const label = alphabet[i] || (i + 1);
          rowsHtml += `
            <tr>
                <td style="text-align:center; font-weight:bold;">${label}</td>
                <td style="padding:8px; text-align:center;">${formatarTexto(stdDates[i])}</td>
            </tr>`;
      }
      calendarioHtml = buildTable("GRUPOS", "SAÍDAS PREVISTAS", null, rowsHtml);
  }

  else if (validadeDates.length > 0) {
      let rowsHtml = `<tr><td style="padding:15px; text-align:center;">${formatarTexto(validadeDates[0])}</td></tr>`;
      calendarioHtml = buildTable(null, "PERÍODO DE VALIDADE", null, rowsHtml);
  }

  results.push({
    json: {
      ...original,
      calendarioHtml: calendarioHtml || ""
    }
  });
}

function buildTable(col1, col2, col3, rows) {
    const header1 = col1 ? `<th style="text-align:center; padding:8px; background-color:#f4f4f4;">${col1}</th>` : "";
    const header3 = col3 ? `<th style="text-align:center; padding:8px; background-color:#f4f4f4;">${col3}</th>` : "";
    const col2Attr = col1 ? "" : "width='100%'";

    return `
    <div style="flex:1 1 48%; min-width:320px; margin-bottom: 20px;">
        <h3 style="color: #ff6600; font-family: Helvetica; font-size: 18pt; text-align: center; margin-bottom: 10px;">
        <strong>CALENDÁRIO DE PARTIDAS</strong>
        </h3>
        <table width="100%" border="1" style="border-collapse:collapse; font-family:Helvetica; border-color:#ccc; font-size:14px;">
            <thead>
                <tr style="background-color:#f4f4f4;">
                    ${header1}
                    <th ${col2Attr} style="text-align:center; padding:10px;">${col2}</th>
                    ${header3}
                </tr>
            </thead>
            <tbody>
                ${rows}
            </tbody>
        </table>
    </div>`;
}

return results;

