const allItems = $input.all();
let results = [];

// Função para limpar texto
function normalize(s) {
  return String(s || "")
    .replace(/\u00A0/g, " ")
    .replace(/[\r\n]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

// Função para definir prioridade de exibição das colunas
function getColumnPriority(key) {
  const lower = key.toLowerCase();
  if (lower.includes("standard")) return 1;
  if (lower.includes("superior")) return 2;
  if (lower.includes("luxo")) return 3;
  if (lower.includes("deluxe")) return 4;
  if (lower.includes("hotel")) return 5;
  if (lower.includes("opção") || lower.includes("opcao")) return 10; 
  return 100;
}

for (const item of allItems) {
  const data = item.json.hoteisNormalized || {};
  const cidades = Array.isArray(data.cidades) ? data.cidades : [];

  // --- 1. Aviso de sem dados ---
  if (!cidades.length) {
    results.push({
      json: {
        ...item.json,
        hoteisHtml: `
        <h3 style="text-align:center; color:#ff6600; font-family:Helvetica; font-size:18pt;">
          <strong>HOTÉIS PREVISTOS OU SIMILARES</strong>
        </h3>
        <p style="text-align:center;"><em>Nenhuma informação disponível.</em></p>
        `
      }
    });
    continue;
  }

  // --- 2. Descobrir colunas dinâmicas ---
  let foundKeys = new Set();
  cidades.forEach(c => {
    if (Array.isArray(c.standard) && c.standard.length) foundKeys.add("Standard");
    if (Array.isArray(c.superior) && c.superior.length) foundKeys.add("Superior");
    if (c.outrasOpcoes) {
      Object.keys(c.outrasOpcoes).forEach(k => foundKeys.add(k));
    }
  });

  if (foundKeys.size === 0) foundKeys.add("Hotel");

  const columns = Array.from(foundKeys).sort((a, b) => {
    const pA = getColumnPriority(a);
    const pB = getColumnPriority(b);
    if (pA !== pB) return pA - pB;
    return a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' });
  });

  // --- 3. Cabeçalho ---
  const headerColsHtml = columns.map(colName => 
    `<th style="text-align:center; padding:10px;">${colName}</th>`
  ).join("");

  // --- 4. Linhas com Lógica de Mesclagem Otimizada ---
  const linhasHtml = cidades.map((c, index) => {
    const cidade = normalize(c.cidade);
    const noites = normalize(c.noites);
    const bgColor = index % 2 === 0 ? "#ffffff" : "#f9f9f9";

    // 4.1 Prepara valores
    let rowValues = columns.map(colKey => {
      let val = "";
      const keyLower = colKey.toLowerCase();
      if (c[keyLower] && Array.isArray(c[keyLower])) {
        val = c[keyLower][0];
      } else if (c.outrasOpcoes && c.outrasOpcoes[colKey]) {
        val = c.outrasOpcoes[colKey][0];
      }
      return normalize(val);
    });

    // 4.2 Lógica de Mesclagem (COLSPAN)
    let cellsHtml = "";
    const nonEmptyValues = rowValues.filter(v => v !== "");
    const uniqueValues = [...new Set(nonEmptyValues)];

    // CENÁRIO A: Valor Único Global (Centraliza tudo)
    // Ex: Só tem "Hotel X" preenchido em uma coluna e as outras 2 estão vazias -> Ocupa tudo.
    if (uniqueValues.length === 1 && columns.length > 1 && nonEmptyValues.length > 0) {
       cellsHtml = `<td colspan="${columns.length}" style="text-align:center; padding:8px; vertical-align: middle;">${uniqueValues[0]}</td>`;
    } 
    else {
      // CENÁRIO B: Mesclagem Inteligente (Conquista Vizinhos Vazios)
      for (let i = 0; i < rowValues.length; i++) {
        let txt = rowValues[i];
        let spanCount = 1;

        // Loop: Olha para a direita.
        // Mescla se: O próximo for IGUAL ao atual OU se o próximo for VAZIO (e o atual não)
        while (
            i + spanCount < rowValues.length && 
            (
                rowValues[i + spanCount] === txt || 
                (txt !== "" && rowValues[i + spanCount] === "")
            )
        ) {
          spanCount++;
        }

        if (spanCount > 1) {
          cellsHtml += `<td colspan="${spanCount}" style="text-align:center; padding:8px; vertical-align: middle;">${txt}</td>`;
          i += (spanCount - 1); 
        } else {
          cellsHtml += `<td style="text-align:center; padding:8px; vertical-align: middle;">${txt}</td>`;
        }
      }
    }

    return `
      <tr style="background-color: ${bgColor};">
        <td style="text-align:center; padding:8px; vertical-align: middle; font-weight:bold;">${cidade}</td>
        <td style="text-align:center; padding:8px; vertical-align: middle;">${noites}</td>
        ${cellsHtml}
      </tr>
    `;
  }).join("");

  // --- 5. HTML Final ---
  const hoteisHtml = `
  <div style="flex: 1 1 48%; min-width: 320px; box-sizing: border-box; margin-bottom: 20px;">
    <h3 style="text-align:center; color:#ff6600; font-family:Helvetica; font-size:18pt; margin-bottom:10px;">
      <strong>HOTÉIS PREVISTOS OU SIMILARES</strong>
    </h3>

    <table width="100%" border="1" style="border-collapse:collapse; font-family:Helvetica; border-color:#ccc; font-size:14px;">
      <thead style="background-color:#f4f4f4;">
        <tr>
          <th style="text-align:center; padding:10px; width:20%;">Cidade</th>
          <th style="text-align:center; padding:10px; width:10%;">Noites</th>
          ${headerColsHtml}
        </tr>
      </thead>
      <tbody>
        ${linhasHtml}
      </tbody>
    </table>
  </div>
  `;

  results.push({
    json: {
      ...item.json,
      hoteisHtml
    }
  });
}

return results;

