// Função para limpar HTMLs removendo \n, \r e múltiplos espaços
function limparHtml(html) {
  if (!html) return "";
  return String(html)
    .replace(/\\n|\\r/g, " ")    // remove \n e \r literais
    .replace(/[\n\r]+/g, " ")    // remove quebras reais
    .replace(/\s{2,}/g, " ")     // remove espaços duplos+
    .replace(/\s*>/g, ">")       // remove espaços antes de >
    .replace(/<\s+/g, "<")       // remove espaços depois de <
    .trim();
}

const CAMPOS_HTML = [
  "tituloAHtml",
  "previaHtml",
  "itinerarioHtml",
  "ObservacoesHtml",
  "documentosHtml",
  "incluiHtml",
  "naoIncluiHtml",
  "calendarioHtml",
  "hoteisHtml",
  "itinerarioArray"
];

for (const item of allItems) {
  const json = { ...item.json };

  // 1) Limpa os campos HTML existentes
  for (const campo of CAMPOS_HTML) {
    if (json[campo]) {
