function parseTitulo(t) {
  if (!t) return [null, null, null];

  const s = String(t).trim();

  // 1) Primeiro tenta achar "X dias"
  let match = s.match(/(\d+\s*dias?.*)/i);

  // 2) Se não encontrar, tentar mês+ano (com ou sem espaço)
  if (!match) {
    match = s.match(/((Jan|Fev|Mar|Abr|Mai|Jun|Jul|Ago|Set|Out|Nov|Dez)\s*\d{4}.*)$/i);
  }

  if (match) {
    const idx = s.indexOf(match[1]);

    const nome = s
      .slice(0, idx)
      .trim()
      .replace(/[-–—]\s*$/, "")
      .trim();

    const info = s.slice(idx).trim();

    return [s, nome, info];
  }

  // fallback
  return [s, s, null];
}

