function parsePrevia(input) {
    if (!input) return ["", "", "", ""];

    // Limpeza inicial
    const full = String(input)
        .replace(/\r|\n/g, " ")
        .replace(/\s+/g, " ")
        .trim();

    const arr = [full, "", "", ""];

    // -------------------------------------------------------
    // 1️⃣ Extrai MÍNIMO
    // -------------------------------------------------------
    const minMatch = full.match(/M[ií]nimo\s+de\s+\d+\s+participantes?/i);
    if (minMatch) arr[2] = minMatch[0].trim();

    let semMinimo = arr[2] ? full.replace(arr[2], "").trim() : full;

    // -------------------------------------------------------
    // 2️⃣ SEPARAÇÃO DINÂMICA (SCHEDULE vs CIDADES)
    // -------------------------------------------------------

    let splitIndex = -1;

    // AQUI ESTÁ A MÁGICA: Lista de prioridades de corte.
    // O código tenta casar esses padrões para saber onde acaba a data e começa a cidade.
    const padroesDeCorte = [
        // 1. Padrões explícitos de calendário
        /calendários?\s+de\s+saídas[\.:]?/i,
        /calendários?\s+de\s+partidas[\.:]?/i,

        // 2. Padrões de dias da semana (NOVO: Resolve o seu erro)
        // Procura por: "Aos Domingos", "Às Terças-feiras", "Toda Segunda", etc.
        /(?:Aos?|Às?|Nas?|Toda?s?)\s+(?:Segundas?|Terças?|Quartas?|Quintas?|Sextas?|Sábados?|Domingos?)(?:-feiras?)?/i,

        // 3. Padrões de frequência simples
        /saídas\s+diárias[\.:]?/i,
        /\bdiariamente\b/i,
        /\bdiárias\b/i,

        // 4. Palavra chave "partidas" solta
        /\bpartidas\b/i,

        // 5. Último recurso: Ponto final seguido de Maiúscula
        /\.\s+(?=[A-Z])/
    ];

    for (const regex of padroesDeCorte) {
        const match = semMinimo.match(regex);
        if (match) {
            // O corte acontece logo após o padrão encontrado
            splitIndex = match.index + match[0].length;
            break; 
        }
    }

    if (splitIndex > -1) {
        // --- Parte 3: TEXTO DE SAÍDAS ---
        let textoSaidas = semMinimo.substring(0, splitIndex).trim();

        // Remove prefixo "Saídas:" e limpa pontuação final
        textoSaidas = textoSaidas.replace(/^Sa[ií]das:\s*/i, "").trim();
        if (textoSaidas.endsWith(".")) textoSaidas = textoSaidas.slice(0, -1);

        arr[3] = textoSaidas;

        // --- Parte 1: CIDADES ---
        let textoCidades = semMinimo.substring(splitIndex).trim();
        arr[1] = textoCidades;
    } else {
        // Fallback TOTAL
        let rawContent = semMinimo.replace(/^Sa[ií]das:\s*/i, "");
        arr[1] = rawContent;
        arr[3] = "Consulte calendário";
    }

    // -------------------------------------------------------
    // 3️⃣ LIMPEZA FINAL DAS CIDADES
    // -------------------------------------------------------
    if (arr[1]) {
        arr[1] = arr[1]
            // Remove aviões, setas e traços
            .replace(/[✈•→—\-]/g, " ") 
            // Remove palavras de ligação que podem ter sobrado no início (ex: "Aos...")
            .replace(/^(Aos?|Às?|Nas?)\s+/i, "")
            // Limpa espaços duplos
            .replace(/\s+/g, " ")
            .trim();
    }

    return arr;
}

