    // AJUSTE 1: Regex de Dias mais estrita
    const dayBlockRegex = /(?:^|[\r\n]+)(\d+(?:º|o)?\s*dia\s*[–—-][\s\S]*?)(?=(?:^|[\r\n]+)\d+(?:º|o)?\s*dia\s*[–—-]|\s*$)/gi;

