        if (/^[\.\s]+$/.test(linhaCabecalhoOriginal) && linhas[1]) {
            linhaCabecalhoOriginal = linhas[1];
            restanteDoBloco = linhas.slice(2).join("\n").trim();
        }

        let corteIndex = Infinity;
        const linhaLower = linhaCabecalhoOriginal.toLowerCase();

        for (const p of proibidosCidade) {
            const idx = linhaLower.indexOf(p.toLowerCase());
            if (idx !== -1 && idx < corteIndex) {
                corteIndex = idx;
            }
        }

        let parteCidades = "";
        let parteTextoNaPrimeiraLinha = "";

        if (corteIndex !== Infinity) {
            parteCidades = linhaCabecalhoOriginal.substring(0, corteIndex).trim();
            parteTextoNaPrimeiraLinha = linhaCabecalhoOriginal.substring(corteIndex).trim();
        } else {
            parteCidades = linhaCabecalhoOriginal;
        }

        const rawParts = parteCidades.split(/(\/|\.\.\.)/).map(p => p.trim()).filter(Boolean);
        const tokensCidades = [];

        for (const rawPart of rawParts) {
            if (rawPart === "/" || rawPart === "...") {
