            }
            const tokenLimpo = limparTokenCidade(rawPart);
            if (tokenLimpo && /[A-ZÁÉÍÓÚÂÊÔÃÕÇ]/.test(tokenLimpo.charAt(0))) {
                tokensCidades.push(tokenLimpo);
            }
        }

        const diaArrayFinal = [diaNumStr, diaLabel, "- "];
        tokensCidades.forEach(t => diaArrayFinal.push(t));

        let conteudoFinal = restanteDoBloco;
        if (parteTextoNaPrimeiraLinha) {
            conteudoFinal = (parteTextoNaPrimeiraLinha + " " + conteudoFinal).trim();
        }
        if (!conteudoFinal && tokensCidades.length === 0) {
             conteudoFinal = resto; 
        }

        // ==================== 4. CORTE BRUTO (Dentro do dia) ====================
        for (const regex of termosProibidos) {
            const match = conteudoFinal.match(regex);
