                // Corta o texto no início da palavra encontrada
                conteudoFinal = conteudoFinal.substring(0, match.index).trim();
            }
        }

        dias.push({
            dia: diaArrayFinal,
            tituloDia: diaArrayFinal.join(" ").trim(), 
