function parseObservacoes(texto) {
  if (!texto) return [];

  // Normaliza tudo
  texto = String(texto)
    .replace(/^Observa[cç][oõ]es?\s*:?\s*/i, "")
    .replace(/\r/g, "\n")
    .replace(/\\n/g, "\n");

  const linhas = texto
    .split("\n")
    .map(l => l.trim())
    .filter(l => l);

  const resultados = [];
  let bloco = { titulo: null, itens: [] };

  const isTitulo = (l) => /^[A-Za-zÀ-ÿ ]+:\s*$/.test(l);

  const limparItem = (str) => {
    return str
      .replace(/\s+/g, " ") // normaliza espaços
      .replace(/\s*\.\s*$/, ".") // garante apenas um .
      .replace(/,\.$/, ".") // corrige ",."
      .trim();
  };

  for (let linha of linhas) {
    // 1) Título detectado
    if (isTitulo(linha)) {
      if (bloco.itens.length > 0 || bloco.titulo !== null) {
        resultados.push(bloco);
      }
      bloco = {
        titulo: linha.replace(/:$/, "").trim(),
        itens: []
      };
      continue;
    }

    // 2) Fragmenta por ponto final
    const frases = linha
      .split(".")
      .map(f => f.trim())
      .filter(f => f.length > 0);

    for (let f of frases) {
      const item = limparItem(f + ".");
      if (item.length > 1) bloco.itens.push(item);
    }
  }

  // adiciona o último bloco
  if (bloco.itens.length > 0 || bloco.titulo !== null) {
    resultados.push(bloco);
  }

  return resultados;
}

