function parseDocumentos(raw) {
    if (!raw) return [];

    // ===== NORMALIZAÇÃO =====
    let text = String(raw)
        .replace(/^Documentos\s*:?\s*/i, "") // remove "Documentos:"
        .replace(/\\n/g, "\n")               // transforma \n literal em quebra real
        .replace(/\r/g, "\n")
        .trim();

    // ===== PRIMEIRA QUEBRA POR LINHAS =====
    let linhas = text
        .split("\n")
        .map(l => l.trim())
        .filter(Boolean);

    // ===== SEGUNDA DIVISÃO: FRASES COMPLETAS =====
    let partes = linhas.flatMap(l =>
        l.split(/(?<=\.)\s+(?=[A-ZÁÉÍÓÚÂÊÔÃÕÇ])/)
    );

    partes = partes
        .map(p => p.trim())
        .filter(Boolean);

    // ===== AGRUPAMENTO DE FRASES =====
    const documentosNormais = [];
    const comestrela = [];

    for (const p of partes) {
        if (p.includes("*")) {
            // separa cada trecho que começa com * como item individual
            const trechos = p.split(/\*\s+/).filter(Boolean);
            trechos.forEach(t => comestrela.push(t.trim()));
        } else {
            documentosNormais.push(p);
        }
    }

    // ===== RETORNA NO FORMATO DE DOCUMENTOSARRAY =====
    const documentosArray = [...documentosNormais];

    if (comestrela.length) {
        documentosArray.push({
            titulo: "comestrela",
            itens: comestrela
        });
    }

    return documentosArray;
}

