  texto = texto.replace(/^Pacote Inclui\s*/i, "");

  // Insere QUEBRA DE LINHA antes de títulos conhecidos
  texto = texto.replace(/(Na [A-Za-zÀ-ÿ ]+:)/gi, "\n$1\n");
  texto = texto.replace(/(No [A-Za-zÀ-ÿ ]+:)/gi, "\n$1\n");

  // Quebra genérica adicional
  texto = texto.replace(/([A-Za-zÀ-ÿ ]+:)(?=\s*[A-ZÀ-ÿ])/g, "$1\n");

  const linhas = texto
    .split("\n")
    .map(l => l.trim())
    .filter(l => l.length > 0);

  const resultados = [];
  let bloco = { titulo: "Pacote Inclui", itens: [] };

  // ❗️ Nova regra correta dos TÍTULOS
  const isTitulo = (l) => /^N[ao]\s+[A-Za-zÀ-ÿ\s]+:\s*$/i.test(l);

  const limparLinha = (l) =>
    l.replace(/^\s*[-•*]+\s*/, "").trim();

  const limparItem = (str) => {
    return str
      .replace(/\s+/g, " ")
      .replace(/\s*\.\s*$/, ".")
      .replace(/,\.$/, ".")
      .trim();
  };

  for (let linha of linhas) {

    // ─────────── TÍTULO ───────────
    if (isTitulo(linha)) {

      // Fecha bloco anterior se tinha conteúdo
      if (bloco.itens.length > 0 || bloco.titulo !== "Pacote Inclui") {
        resultados.push(bloco);
      }

      bloco = {
        titulo: linha.replace(/:$/, "").trim(),
        itens: []
      };

      continue;
    }

    // ─────────── ITENS ───────────
    let semBullet = limparLinha(linha);

    const frases = semBullet
      .split(".")
      .map(f => f.trim())
      .filter(f => f);

    for (let f of frases) {
      bloco.itens.push(limparItem(f + "."));
    }
  }

  resultados.push(bloco);

  return resultados;
}

// NODE EXEC
const out = $input.all().map(item => {
  const raw = item.json.inclui || item.json["inclui"] || "";
  item.json.incluiParsed = parseInclui(raw);
  return item;
});

return out;

function parseNaoInclui(raw) {
  if (!raw) return [];

  let texto = String(raw)
    .replace(/\r/g, "\n")
    .replace(/\\n/g, "\n")
    .trim();

  texto = texto.replace(/^Não Inclui\s*/i, "");

  // 🔥 NOVO STOP: corta tudo no primeiro "*"
  const posAsterisco = texto.indexOf("*");
  if (posAsterisco !== -1) {
    texto = texto.substring(0, posAsterisco).trim();
  }

  // Agora quebra em linhas (já limpas do lixo)
  let linhasBrutas = texto
    .split("\n")
    .map(l => l.trim())
    .filter(l => l.length > 0);

  const limparLinha = (l) =>
    l.replace(/^\s*[-•*]+\s*/, "").trim();

  const limparItem = (str) => {
    return str
      .replace(/\s+/g, " ")
      .replace(/\s*\.\s*$/, ".")
      .replace(/,\.$/, ".")
      .trim();
  };

  const resultados = [];
  let bloco = { titulo: "Não Inclui", itens: [] };

  for (let linha of linhasBrutas) {
    let semBullet = limparLinha(linha);

    const frases = semBullet
      .split(".")
      .map(f => f.trim())
      .filter(f => f);

    for (const f of frases) {
      bloco.itens.push(limparItem(f + "."));
    }
  }

  resultados.push(bloco);

  return resultados;
}


// EXEC NODE
const out = $input.all().map(item => {
  const json = (typeof item.json === "object" && item.json !== null)
    ? item.json
    : {};

  const raw = json.naoInclui || json["naoInclui"] || "";

  json.naoIncluiParsed = parseNaoInclui(raw);

  return { json };
});

return out;

// =====================================================================
// PARSER HÍBRIDO: SUPORTA TABELAS COMPLEXAS, SIMPLES E SEM CABEÇALHO
// =====================================================================
const allItems = $input.all();

// ================= HELPER FUNCTIONS =================
function cleanText(s) {
    if (s === null || s === undefined) return "";
    return String(s)
        .replace(/&nbsp;/g, " ")
        .replace(/<br\s*\/?>/gi, " | ") // Transforma BR em separador para não colar palavras
        .replace(/<[^>]+>/g, "")     
        .replace(/\s+/g, " ")        
        .trim();
}

function normalizeList(val) {
    if (Array.isArray(val)) return val.map(cleanText).filter(Boolean);
    if (val) return [cleanText(val)];
    return [];
}

// Extrai tabela HTML
function extractFirstTable(html) {
    if (!html || typeof html !== "string") return "";
    const m = html.match(/<table[\s\S]*?<\/table>/i);
    return m ? m[0] : "";
}

// ================= LÓGICA CONDICIONAL DE PARSING =================
function parseTableHtmlToCities(tableHtml) {
    if (!tableHtml) return [];

    // 1. Extrai TODAS as linhas e células (matriz bruta)
    const rowRe = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
    const cellRe = /<(td|th)[^>]*>([\s\S]*?)<\/\1>/gi;

    const allRows = [];
    let r;
    while ((r = rowRe.exec(tableHtml)) !== null) {
        const cells = [];
        let c;
        const rowInner = r[1];
        while ((c = cellRe.exec(rowInner)) !== null) {
            cells.push(cleanText(c[2])); // Pega o conteúdo limpo
        }
        if (cells.length > 0) allRows.push(cells);
    }

    if (allRows.length < 2) return [];

    // =========================================================
    // AQUI ESTÁ A LÓGICA CONDICIONAL (VARIAVEL)
    // =========================================================

    let headerRowIndex = -1;
    let idxCidade = -1;
    let idxNoites = -1;

    // ESTRATÉGIA 1: Busca Semântica (Procura palavras-chave)
    // Isso resolve o caso da tabela com Título na linha 0
    for (let i = 0; i < Math.min(5, allRows.length); i++) { // Olha só as primeiras 5 linhas
        const rowLower = allRows[i].map(c => c.toLowerCase());

        // Verifica se a linha parece um cabeçalho
        const cIndex = rowLower.findIndex(c => c.includes("cidade") || c.includes("city") || c === "destinos");
        const nIndex = rowLower.findIndex(c => c.includes("noite") || c.includes("night") || c === "nts");

        if (cIndex !== -1 && nIndex !== -1) {
            headerRowIndex = i;
            idxCidade = cIndex;
            idxNoites = nIndex;
            break; // Achou! Para de procurar.
        }
    }

    // ESTRATÉGIA 2: Fallback Posicional (Se a Estratégia 1 falhar)
    // Assume que a estrutura é padrão: Linha 0 ou 1 é cabeçalho
    if (headerRowIndex === -1) {
        // Se a linha 0 tem apenas 1 célula (ex: Título com Colspan), tenta a linha 1
        if (allRows[0].length === 1 && allRows.length > 1) {
            headerRowIndex = 1;
        } else {
            headerRowIndex = 0;
        }
        // Assume posições padrão se não achou chaves
        idxCidade = 0;
        idxNoites = 1;
    }

    // =========================================================
    // MAPEAMENTO DINÂMICO DE COLUNAS
    // =========================================================
    const headerRowData = allRows[headerRowIndex];
    const columnMap = [];

    // Mapeia o que é cada coluna baseada no cabeçalho encontrado
    for (let i = 0; i < headerRowData.length; i++) {
        if (i === idxCidade || i === idxNoites) continue;

        let title = headerRowData[i];
        // Se não tiver título (coluna vazia), inventa um nome para não perder o dado
        if (!title) title = `Opção ${columnMap.length + 1}`;

        columnMap.push({ index: i, title: title });
    }

    const out = [];

    // =========================================================
    // EXTRAÇÃO DOS DADOS
    // =========================================================
    for (let i = headerRowIndex + 1; i < allRows.length; i++) {
        const row = allRows[i];
        // Proteção: Pula linhas vazias
        if (row.length < 2) continue; 
        // Proteção: Pula repetição de cabeçalho no meio da tabela
        if (row[idxCidade] && (row[idxCidade].toLowerCase().includes("cidade") || row[idxCidade].toLowerCase().includes("city"))) continue;

        const city = row[idxCidade] || "";
        const nights = row[idxNoites] || "";

        const item = { 
            cidade: city, 
            noites: nights, 
            standard: [], superior: [], luxo: [], hotel: [], 
            outrasOpcoes: {} 
        };

        columnMap.forEach(col => {
            // Se a linha for mais curta que o cabeçalho, evita erro
            const val = row[col.index] || ""; 
            if (!val) return;

            const ti = col.title.toLowerCase();

            // Roteamento inteligente das categorias
            if (ti.includes("standard")) item.standard.push(val);
            else if (ti.includes("superior")) item.superior.push(val);
            else if (ti.includes("luxo") || ti.includes("luxury")) item.luxo.push(val);
            // Cuidado com a palavra "Hotel" que pode aparecer em nomes de hoteis
            else if (ti.includes("hotel") && !ti.includes("azul") && !ti.includes("cairo")) item.hotel.push(val);
            else {
                // Tudo que sobra (Opção I, II, III...) vai para cá
                const key = col.title.trim();
                if (!item.outrasOpcoes[key]) item.outrasOpcoes[key] = [];
                item.outrasOpcoes[key].push(val);
            }
        });

        if (city || item.standard.length > 0 || Object.keys(item.outrasOpcoes).length > 0) {
            out.push(item);
        }
    }

    return out;
}

function normalizeCitiesArray(arr) {
    return (arr || []).map(c => {
        return {
            cidade: cleanText(c.cidade || c.city || ""),
            noites: cleanText(c.noites || c.nights || ""),
            standard: normalizeList(c.standard),
            superior: normalizeList(c.superior),
            luxo: normalizeList(c.luxo || c.luxury),
            hotel: normalizeList(c.hotel),
            outrasOpcoes: c.outrasOpcoes || {}
        };
    });
}

// ================= PROCESSAMENTO PRINCIPAL =================
const results = [];

for (const item of allItems) {
    let out = { cidades: [] };
    let json = (item && item.json) ? item.json : {};

    // 1. Normaliza Localização do Payload
    if (json.data) json = json.data;
    else if (json.result) json = json.result;
    else if (json.payload) json = json.payload;

    let htmlSrc = "";

    // 2. Detecta se é HTML string ou Objeto JSON
    if (typeof json === "string" && json.includes("<table")) htmlSrc = json;
    else if (json.hoteis && typeof json.hoteis === "string") htmlSrc = json.hoteis;
    else if (json.html && typeof json.html === "string") htmlSrc = json.html;
    else if (json.hoteisHtml && typeof json.hoteisHtml === "string") htmlSrc = json.hoteisHtml;

    // CENÁRIO A: É HTML (Vai para o Parser Híbrido)
    if (htmlSrc) {
        const table = extractFirstTable(htmlSrc);
        const parsedCities = parseTableHtmlToCities(table);
        out.cidades = normalizeCitiesArray(parsedCities);
        results.push({ json: { ...item.json, hoteisNormalized: out } });
        continue;
    }

    // CENÁRIO B: É JSON Estruturado (Usa direto)
    if (Array.isArray(json.cidades)) {
        out.cidades = normalizeCitiesArray(json.cidades);
        results.push({ json: { ...item.json, hoteisNormalized: out } });
        continue;
    }

    // CENÁRIO C: Objeto Hoteis > Hoteis
    if (json.hoteis && json.hoteis.hoteis && Array.isArray(json.hoteis.hoteis)) {
        out.cidades = normalizeCitiesArray(json.hoteis.hoteis);
        results.push({ json: { ...item.json, hoteisNormalized: out } });
        continue;
    }

    // CENÁRIO D: Fallback para Estruturas Planas (Standard/Superior soltos)
    if (Array.isArray(json.standard) || Array.isArray(json.superior)) {
         const cityNames = Array.isArray(json.cidade) ? json.cidade : [];
         const maxLen = Math.max(cityNames.length, (json.standard||[]).length, (json.superior||[]).length);
         const fallback = [];
         for(let i=0; i<maxLen; i++){
             fallback.push({
                 cidade: cityNames[i] || "",
                 noites: "",
                 standard: json.standard ? [json.standard[i]] : [],
                 superior: json.superior ? [json.superior[i]] : [],
                 outrasOpcoes: {}
             });
         }
         out.cidades = normalizeCitiesArray(fallback);
         results.push({ json: { ...item.json, hoteisNormalized: out } });
         continue;
    }

    // Se falhar tudo
    results.push({ json: { ...item.json, hoteisNormalized: { cidades: [] }, notice: "Formato não reconhecido" } });
}

return results;

// ===================================================
// PARSE DE CALENDÁRIO ROBUSTO (CORRIGIDO)
// ===================================================

const allItems = $input.all();
let results = [];

// -----------------------------------------
// 1. Utilitários de Texto e HTML
// -----------------------------------------
function cleanText(s) {
    if (!s) return "";
    return String(s)
        .replace(/\s+/g, " ")
        .replace(/&nbsp;/g, " ")
        .trim();
}

function extractTables(html) {
    if (!html || typeof html !== "string") return [];
    return html.match(/<table[\s\S]*?<\/table>/gi) || [];
}

function parseHtmlTable(tableHtml) {
    const rowRe = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
    const cellRe = /<(td|th)[^>]*>([\s\S]*?)<\/\1>/gi;

    const rows = [];
    let rowMatch;

    while ((rowMatch = rowRe.exec(tableHtml)) !== null) {
        const rowCells = [];
        let cellMatch;
        cellRe.lastIndex = 0; 

        while ((cellMatch = cellRe.exec(rowMatch[1])) !== null) {
            let txt = cleanText(
                cellMatch[2]
                    .replace(/<br\s*\/?>/gi, " ||BR|| ") 
                    .replace(/<[^>]+>/g, "") 
            ).replace(" ||BR|| ", " "); 

            rowCells.push(txt);
        }
        if (rowCells.length) rows.push(rowCells);
    }
    return rows;
}

// -----------------------------------------
// 2. Configurações de Filtragem
// -----------------------------------------

const BLACKLIST_ROW_START = [
    "criança", "suplemento", "serviço opcional", 
    "traslado", "ticket", "aéreo interno"
];

const BLACKLIST_CELL_CONTENT = [
    "valor", "preço", "price", "aéreo" 
];

const REGEX_PRECO = /(\d{1,3}\.\d{3},\d{2}|US\$|USD\s+\d)/;

// -----------------------------------------
// 3. Processamento Lógico
// -----------------------------------------
function processTable(rawRows) {
    if (!rawRows || rawRows.length === 0) return [];

    let cleanRows = rawRows.filter(row => {
        if (!row || row.length === 0) return false;

        const firstCell = (row[0] || "").toLowerCase();
        const rowString = row.join("").trim();
        if (rowString === "") return false;

        if (BLACKLIST_ROW_START.some(term => firstCell.includes(term))) return false;
        if ((firstCell.includes("preço") || firstCell.includes("valor")) && firstCell.length < 25) return false;

        return true;
    });

    if (cleanRows.length === 0) return [];

    cleanRows = cleanRows.map(row => {
        return row.map(cell => {
            const cLower = cell.toLowerCase();
            if (REGEX_PRECO.test(cell) && !cell.includes("/")) return ""; 
            if (BLACKLIST_CELL_CONTENT.some(term => cLower === term)) return "";
            return cell;
        });
    });

    const numCols = Math.max(...cleanRows.map(r => r.length));
    const keepColIndices = [];

    for (let col = 0; col < numCols; col++) {
        let hasData = false;
        for (let row of cleanRows) {
            if (row[col] && row[col].trim().length > 1) {
                hasData = true;
                break;
            }
        }
        if (hasData) keepColIndices.push(col);
    }

    const finalTable = cleanRows.map(row => {
        return keepColIndices.map(index => row[index] || "");
    });

    return finalTable;
}

// -----------------------------------------
// EXECUÇÃO
// -----------------------------------------
for (const item of allItems) {
    const originalJson = item.json || {};
    const htmlSource = originalJson.calendario || JSON.stringify(originalJson); 

    let calendariosFiltrados = [];
    const tables = extractTables(htmlSource);

    for (const t of tables) {
        if (t.toLowerCase().includes("opcional") && !t.toLowerCase().includes("calendário")) continue;

        const rawRows = parseHtmlTable(t);
        const processed = processTable(rawRows);

        // --- VALIDAÇÃO DE CONTEÚDO (ATUALIZADA) ---
        const temConteudo = processed.some(row => 
            row.some(c => 
                /\d{4}/.test(c) ||                               // Ano (2025/2026)
                /sa[ií]da/i.test(c) ||                           // Palavra Saída
                /validade/i.test(c) ||                           // Palavra Validade
                /período/i.test(c) ||                            // Palavra Período
                /feiras/i.test(c) ||                             // Dias da semana
                /\d{2}\s*,\s*\d{2}/.test(c) ||                   // Datas "01, 08"
                /\d{2}\/?[a-zA-Zçãó]+?\s+a\s+\d{2}/i.test(c)     // NOVO: "02/Janeiro a 30/Dezembro"
            )
        );

        if (processed.length > 0 && temConteudo) {
            calendariosFiltrados.push({
                linhas: processed
            });
        }
    }

    results.push({
        json: {
            ...originalJson,
            calendarios: calendariosFiltrados
        }
    });
}

return results;

// ==================== MERGE DRIVE + DOCS (versão robusta com tabelas HTML) ====================
const items = $input.all();

// ------ helpers ------
function normalizeText(s){
  return String(s || '')
    .replace(/\r/g, '')
    .replace(/\n\s*\n/g, '\n\n')
    .replace(/\s{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// Extrai parágrafos do objeto do Google Docs (body.content)
function extractParagraphsFromDoc(doc){
  const body = doc.body || doc.document || doc;
  let out = [];
  for (const el of body.content || []) {
    if (el.paragraph) {
      for (const e of el.paragraph.elements || []) {
        if (e.textRun?.content) out.push(e.textRun.content);
      }
    }
  }
  return out.join('').trim();
}

// Extrai tabelas diretamente do body.content (forma estruturada)
function extractTablesFromDoc(doc){
  const body = doc.body || doc.document || doc;
  const tables = [];
  for (const el of body.content || []) {
    if (el.table) {
      const table = [];
      for (const row of el.table.tableRows || []) {
        const rowData = [];
        for (const cell of row.tableCells || []) {
          const parts = [];
          for (const c of cell.content || []) {
            if (c.paragraph) {
              for (const e of c.paragraph.elements || []) {
                if (e.textRun?.content) parts.push(e.textRun.content.trim());
              }
            }
          }
          rowData.push(parts.join(' '));
        }
        table.push(rowData);
      }
      tables.push(table);
    }
  }
  return tables;
}

// Converte array de tabela em HTML <table>
function tableArrayToHTML(table){
  if (!table || !table.length) return '';
  let html = '<table border="1" cellspacing="0" cellpadding="4">';
  table.forEach((row, i) => {
    html += '<tr>';
    row.forEach(cell => {
      if (i === 0) {
        html += `<th>${cell || ''}</th>`;
      } else {
        html += `<td>${cell || ''}</td>`;
      }
    });
    html += '</tr>';
  });
  html += '</table>';
  return html;
}

// ====================== CLASSIFICAÇÃO UNIVERSAL DE TABELAS ======================
function classifyTablesUniversal(tables) {
  const result = {
    hoteis: [],
    calendario: [],
    outros: []
  };

  const regexHoteis =
    /(hotel|hot[eé]is|cidade|noites|similares|superior|standard|op[cç][aã]o)/i;

  const regexCalendario =
    /(parte\s+terrestre|pre[cç]os|datas|sa[ií]das|participantes|calend[aá]rio)/i;

  // Tabelas que DEVEM ser marcadas como calendário, nunca como hotéis
  const regexBloqueioHoteis =
    /(pre[cç]os|usd|d[oó]lares|categoria\s+superior|categoria\s+standard|ryokan|mínimo\s+de\s+2)/i;

  tables.forEach(tbl => {
    const flat = tbl.map(row => row.join(" ")).join(" ").toLowerCase();

    // 🔒 Se contém termos de preços → força ser calendário
    if (regexBloqueioHoteis.test(flat)) {
      result.calendario.push(tbl);
      return;
    }

    // 🏨 Hotéis previstos
    if (regexHoteis.test(flat)) {
      result.hoteis.push(tbl);
      return;
    }

    // 📆 Calendário / preços
    if (regexCalendario.test(flat)) {
      result.calendario.push(tbl);
      return;
    }

    // ❔ Qualquer outra tabela
    result.outros.push(tbl);
  });

  return result;
}


// ------ identificar itens do drive e do docs ------
const driveItems = items.filter(i => i.json && i.json.id);
const docItems = items.filter(i => i.json && (i.json.documentId || i.json.data || i.json.body || i.json.content || i.json.fileId));

function findMatchForDrive(drive){
  return docItems.find(doc => {
    const cand = [
      doc.json.documentId,
      doc.json.id,
      doc.json.fileId,
      doc.json.resourceId,
      (doc.json.data && doc.json.data.fileId)
    ].filter(Boolean).map(String);
    return cand.includes(String(drive.json.id));
  });
}

// ----- montar saída -----
const output = driveItems.map(drive => {
  const match = findMatchForDrive(drive);

  let content = '';
  let hoteis = '';
  let calendario = '';
  let observacoesExtra = '';
  let documentosExtra = '';

  if (match) {
    if (match.json.body && Array.isArray(match.json.body.content)) {

      // Texto principal
      content = normalizeText(extractParagraphsFromDoc(match.json));

      // Extrair tabelas estruturadas
      const tables = extractTablesFromDoc(match.json);

      if (tables.length) {

        // 🌟 CLASSIFICAÇÃO UNIVERSAL 🌟
        const classified = classifyTablesUniversal(tables);

        // Converte todas as tabelas
        hoteis = classified.hoteis.map(tableArrayToHTML).join("\n\n");
        calendario = classified.calendario.map(tableArrayToHTML).join("\n\n");

        // Extras opcionais (se existirem)
        classified.outros.forEach(tbl => {
          const flat = tbl.map(row => row.join(" ")).join(" ").toLowerCase();

          if (/observa[cç][oõ]es/.test(flat)) {
            observacoesExtra = tableArrayToHTML(tbl);
          }

          if (/documentos\s+necess[aá]rios/.test(flat)) {
            documentosExtra = tableArrayToHTML(tbl);
          }
        });

      }

    } else {

      // Fallback texto simples
      const raw = match.json.data || match.json.content || match.json.text || match.json.plainText || '';
      content = normalizeText(raw);

      const hoteisRegex = /HOT[ÉE]IS\s+PREVISTOS[\s\S]*?(?=PARTE\s+TERRESTRE)/i;
      const calendarioRegex = /(PARTE\s+TERRESTRE[\s\S]*)/i;

      const hMatch = content.match(hoteisRegex);
      if (hMatch) hoteis = hMatch[0].trim();

      const cMatch = content.match(calendarioRegex);
      if (cMatch) calendario = cMatch[1].trim();
    }
  }

  return {
    json: {
      id: drive.json.id,
      nome: drive.json.name,
      content,
      hoteis,
      calendario,
      observacoesExtra,
      documentosExtra
    }
  };
});

return output;

